struct FfiConverterTypeFFIUploadProgressHandler: FfiConverter {
    fileprivate static let handleMap = UniffiHandleMap<FfiUploadProgressHandler>()

    typealias FfiType = UInt64
    typealias SwiftType = FfiUploadProgressHandler

    public static func lift(_ handle: UInt64) throws -> FfiUploadProgressHandler {
        if ((handle & 1) == 0) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return FfiUploadProgressHandlerImpl(unsafeFromHandle: handle)
        } else {
            // Swift-generated handle, get the object from the handle map
            return try handleMap.remove(handle: handle)
        }
    }

    public static func lower(_ value: FfiUploadProgressHandler) -> UInt64 {
         if let rustImpl = value as? FfiUploadProgressHandlerImpl {
             // Rust-implemented object.  Clone the handle and return it
            return rustImpl.uniffiCloneHandle()
         } else {
            // Swift object, generate a new vtable handle and return that.
            return handleMap.insert(obj: value)
         }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiUploadProgressHandler {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: FfiUploadProgressHandler, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


