struct FfiConverterTypeHFClientFFI: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = HfClientFfi

    public static func lift(_ handle: UInt64) throws -> HfClientFfi {
        return HfClientFfi(unsafeFromHandle: handle)
    }

    public static func lower(_ value: HfClientFfi) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HfClientFfi {
