    func listTree(revision: String?, recursive: Bool, expand: Bool, limit: UInt64?) async throws  -> [RepoTreeEntryDto]
    
    func name()  -> String
    
    func owner()  -> String
    
    func repoId()  -> String
    
    /**
     * Download all selected files for a resolved revision. Reuses hf-hub's
     * `snapshot_download` builder; returns the snapshot directory path.
     * Works for every [`RepoTypeDTO`].
     */
    func snapshotDownload(revision: String?, allowPatterns: [String]?, ignorePatterns: [String]?, localDir: String?, forceDownload: Bool, localFilesOnly: Bool, maxWorkers: UInt32?, handle: OperationHandle?, progress: FfiDownloadProgressHandler?) async throws  -> String
    
    /**
     * Update repository settings. Mirrors `HFRepository::update_settings`,
     * dispatched per-`RepoTypeDTO`. Each parameter is `Option<…>` – `None`
     * leaves the corresponding setting untouched on the Hub.
     */
    func updateSettings(`private`: Bool?, gated: GatedApprovalModeDto?, description: String?, discussionsDisabled: Bool?, gatedNotifications: GatedNotificationsDto?) async throws 
    
    /**
     * Upload a single file to this repository in a one-op commit. Mirrors
     * `HFRepository::upload_file`. The source is either a local file path
     * or in-memory bytes via [`UploadSourceDTO`]. Optional `handle` enables
