    typealias SwiftType = DownloadEventDto

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> DownloadEventDto {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .start(totalFiles: try FfiConverterUInt64.read(from: &buf), totalBytes: try FfiConverterUInt64.read(from: &buf)
        )
        
        case 2: return .progress(files: try FfiConverterSequenceTypeFileProgressDTO.read(from: &buf)
        )
        
        case 3: return .aggregateProgress(bytesCompleted: try FfiConverterUInt64.read(from: &buf), totalBytes: try FfiConverterUInt64.read(from: &buf), bytesPerSec: try FfiConverterOptionDouble.read(from: &buf), transferBytesCompleted: try FfiConverterUInt64.read(from: &buf), transferBytes: try FfiConverterUInt64.read(from: &buf), transferBytesPerSec: try FfiConverterOptionDouble.read(from: &buf)
        )
        
        case 4: return .complete
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: DownloadEventDto, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .start(totalFiles,totalBytes):
            writeInt(&buf, Int32(1))
            FfiConverterUInt64.write(totalFiles, into: &buf)
            FfiConverterUInt64.write(totalBytes, into: &buf)
            
        
        case let .progress(files):
            writeInt(&buf, Int32(2))
            FfiConverterSequenceTypeFileProgressDTO.write(files, into: &buf)
            
        
        case let .aggregateProgress(bytesCompleted,totalBytes,bytesPerSec,transferBytesCompleted,transferBytes,transferBytesPerSec):
            writeInt(&buf, Int32(3))
            FfiConverterUInt64.write(bytesCompleted, into: &buf)
            FfiConverterUInt64.write(totalBytes, into: &buf)
